import"./hoisted.D9FO-Yxe.js";const a=document.getElementById("sort-select"),r=document.getElementById("products-grid");if(a&&r){const p=Array.from(r.children);a.addEventListener("change",()=>{const c=Array.from(r.children);if(a.value==="featured"){p.forEach(e=>r.appendChild(e));return}c.sort((e,t)=>{const n=e.querySelector(".product-card"),s=t.querySelector(".product-card"),o=parseFloat(n?.dataset.price||"0"),d=parseFloat(s?.dataset.price||"0"),i=n?.dataset.name||"",l=s?.dataset.name||"";switch(a.value){case"price-asc":return o-d;case"price-desc":return d-o;case"name-asc":return i.localeCompare(l);case"name-desc":return l.localeCompare(i);default:return 0}}),c.forEach((e,t)=>{e.style.animationDelay=`${t*.04}s`,r.appendChild(e)})})}
